easy.solution:
def is_leap_year(year):
    if year % 400 == 0:
        return True
    elif year % 100 == 0:
        return False
    return year % 4 == 0

medium.solution:
def calc_shipping(amount, is_prime):
    if is_prime or amount >= 100:
        return 0
    elif amount >= 50:
        return 5
    else:
        return 10

hard.solution:
def calc_tax(income):
    if income <= 10000:
        return 0.0
    elif income <= 50000:
        return (income - 10000) * 0.10
    else:
        return (40000 * 0.10) + ((income - 50000) * 0.20)

